VALUES
  ('judicial-f0899a01-moex-00216', 'judicial-f0899a01', 'judicial-f0899a01-moex-113-d1a761c9', 'sub-judicial-f0899a01-04', NULL, 'single_choice', '管理機關於開放水域，已就使用該自然公物或人工設施為適當之警告或標示，人民仍從事具危險性活動者， 依國家賠償法規定，下列敘述何者正確？', '["使用人工設施所生之損害，國家不負損害賠償責任", "使用自然公物所生之損害，國家不負損害賠償責任", "無論係使用自然公物或人工設施所生之損害，國家皆應負損害賠償責任", "國家可主張減輕或免除損害賠償責任者，僅限於開放山域，不包括開放水域"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "c6cde154bf91", "answer_pdf_sha1": "5fb072db0e88", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "202", "s": "0303", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00217', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲、乙、丙三人與丁、戊素有怨隙，某日趁丁赴戊宅作客時，甲、乙、
丙三人合議分持棍棒強行進入戊宅中，將丁、戊擊傷（丁、戊二人皆僅
受普通傷害），甲、乙、丙三人在擊傷丁、戊之際，並同時故意砸毀戊宅
客廳中之花瓶、桌椅後離去。案經戊依法向檢察官對甲提出傷害之告訴，
嗣經檢察官偵查終結後對甲提起傷害罪之公訴。關於上開檢察官所提之
公訴，其效力如何？試申論之。（25 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "4e90471b9217", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0516", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00218', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲任職於某地方檢察署擔任法警之工作多年，因執行職務關係，協助檢
察官偵辦某社會矚目之重大刑事案件，因而知悉該案件之部分案情。某
日該案件召開偵查庭前夕，大批新聞媒體記者蜂擁而至，欲採訪該案之
案情，檢察署偵查庭前因而人聲鼎沸人群推擠秩序大亂。甲為維持現場
秩序、避免人群推擠、俾利偵查庭之順利進行，乃於檢察署之門口大廳
回答新聞媒體記者之提問，被動說出該案件涉案者之身分與部分案情。
甲之上開行為是否違反刑事訴訟法之相關規定？試申論之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "4e90471b9217", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0516", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00219', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '甲、乙二人為雙胞胎兄弟，長相體態相似，分居多年。某日丙行走於路
上，遭遇機車搶匪乙將其手持提包搶走，恰遇附近巡邏之司法警察，遂
立即向巡邏之司法警察報案，並坐上警車與司法警察緊追搶匪。追逐中，
丙將乙所騎乘之機車車牌 CBL-110 及乙之長相體態特徵記下並提供巡
邏之司法警察，司法警察透過警用車牌資訊查詢系統查出該車車主丁登
記之住址為附近某民宅。司法警察乃強行進入該民宅內，突見雙胞胎兄
弟之甲坐於客廳中，誤認甲為搶嫌乙，遂將甲逮捕，並於甲身上衣物口
袋內搜得微量安非他命毒品 1小包；另於停放在該民宅附近停車場之車
牌 CBL-110 機車置物箱內搜得改造手槍 1 把，乃予以查扣。司法警察所
實施之上開程序是否合法？所搜得之安非他命毒品、改造手槍有無證據
能力？試申論之。（25分）
20320', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "4e90471b9217", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0516", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00220', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-9a3b44c4', 'sub-judicial-f0899a01-01', NULL, 'essay', '何謂「簡式審判程序」？何謂「簡易判決處刑」？兩者間有何異同？試
申論之。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:45+00:00", "source_pdf_sha1": "4e90471b9217", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0516", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "刑事訴訟法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": "四", "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00221', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何者屬刑法第17條規定的加重結果犯？', '["警察追捕不接受酒駕臨檢的駕駛人，卻導致警車自撞分隔島，員警受傷", "小偷偷走被害人背包，背包中除了錢財外，尚有氣喘藥，後被害人因氣喘發作，藥物被小偷偷走未能及 時服藥而死亡", "駕駛因粗心闖紅燈，雖及時煞車未撞到行人，行人卻因驚嚇而心肌梗塞死亡", "原想給情敵一個教訓，卻在毆打情敵時不小心打到要害而導致情敵傷重死亡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00222', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何種非基於正當目的之接合行為，不該當刑法上之性交？', '["以手指與他人肛門接合", "以雨傘插入他人性器", "以酒瓶插入他人口腔", "以口腔與他人性器接合"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00223', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '下列何者不適用刑法第2條第1項所揭示的從舊從輕原則？', '["有期徒刑", "褫奪公權", "罰金", "沒收"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00224', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '有關「法律明確性原則」或「犯罪構成要件明確性」，下列敘述何者錯誤？', '["刑罰之構成要件應以法律定之，只要法律就其構成要件授權以命令為補充規定，必然違反刑罰明確性原 則而違憲", "犯罪構成要件雖有不確定性，但只要意義並非一般人難以理解、且為受規範者所得預見，並可經由司法 審查加以確認，即不違背犯罪構成要件明確性原則", "犯罪構成要件明確性原則是罪刑法定原則內涵之一", "民國98年1月廢除之檢肅流氓條例有關「欺壓善良」、「品行惡劣」、「遊蕩無賴」等流氓之定義規定， 經司法院解釋認為違反法律明確性原則"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL),
  ('judicial-f0899a01-moex-00225', 'judicial-f0899a01', 'judicial-f0899a01-moex-112-e2754278', 'sub-judicial-f0899a01-02', NULL, 'single_choice', '甲欲行竊，侵入某住居，翻箱倒櫃物色屋內值錢財物。依我國刑法與實務見解，下列敘述何者錯誤？', '["甲侵入後，因不慎觸動警鈴，情急之下鎩羽而歸，甲成立侵入住居竊盜之普通未遂", "甲若成立侵入住居竊盜之普通未遂犯，該行為之處罰，得按既遂犯之刑減輕", "甲因看見牆上貼著「歹路毋通行」，一時心生悔意，遂空手離開盜所，甲成立侵入住居竊盜之中止未遂", "甲若成立侵入住居竊盜之中止未遂犯，該行為之處罰，得減輕或免除其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:46+00:00", "source_pdf_sha1": "d4be12aadcc3", "answer_pdf_sha1": "5836207ad078", "source_family": "moex-gov-tw", "moex": {"exam_code": "112130", "c": "202", "s": "0505", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "112", "exam_name": "112年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "法警"}'::jsonb, NULL)
